// ── Primitives ─────────────────────────────────────────────────────────

function Stepper({ qty, onAdd, onSub }) {
  return (
    <div className="bm-pop" style={{ display:"flex",alignItems:"center",background:EM,borderRadius:24,height:34,minWidth:90,flexShrink:0 }}>
      <button onClick={e=>{e.stopPropagation();onSub();}} aria-label="Decrease" style={{ width:32,height:34,color:"#fff",fontSize:20,border:"none",background:"transparent",cursor:"pointer",lineHeight:1 }}>−</button>
      <span style={{ color:"#fff",fontWeight:800,flex:1,textAlign:"center",fontSize:13 }}>{qty}</span>
      <button onClick={e=>{e.stopPropagation();onAdd();}} aria-label="Increase" style={{ width:32,height:34,color:"#fff",fontSize:20,border:"none",background:"transparent",cursor:"pointer",lineHeight:1 }}>+</button>
    </div>
  );
}

function Pill({ children, color=LM, textColor="#14532D" }) {
  return <span style={{ background:color,color:textColor,fontSize:10,fontWeight:800,padding:"3px 10px",borderRadius:20,display:"inline-flex",alignItems:"center",gap:4,lineHeight:1.4 }}>{children}</span>;
}

function Breadcrumb({ crumbs, nav }) {
  return (
    <div style={{ fontSize:12,color:"#94A3B8",marginBottom:18,display:"flex",gap:4,alignItems:"center",flexWrap:"wrap" }}>
      {crumbs.map((c,i) => (
        <span key={i} style={{ display:"flex",alignItems:"center",gap:4 }}>
          {i > 0 && <span>›</span>}
          <span onClick={c.action} style={{ cursor:c.action?"pointer":"default",color:c.action?EM:"#64748B",fontWeight:c.action?600:400 }}>{c.label}</span>
        </span>
      ))}
    </div>
  );
}

// ── Product Card ───────────────────────────────────────────────────────

function ProductCard({ p, qty, onAdd, onUpdate, nav }) {
  const d = off(p.price, p.mrp);
  return (
    <div data-testid={`product-card-${p.id}`} className="bm-card"
      onClick={() => nav({ type:"product", id:p.id })}
      style={{ background:"#fff",borderRadius:16,border:"1px solid #E2E8F0",padding:10,display:"flex",flexDirection:"column",cursor:"pointer",boxShadow:"0 1px 4px rgba(0,0,0,.04)" }}>
      <div style={{ position:"relative",background:"#F8FAFC",borderRadius:11,aspectRatio:"1",overflow:"hidden",marginBottom:9 }}>
        {d > 0 && <div style={{ position:"absolute",top:6,left:6,background:EM,color:"#fff",fontSize:9,fontWeight:800,padding:"2px 6px",borderRadius:6,zIndex:1 }}>{d}% OFF</div>}
        <img src={p.img} alt={p.name} loading="lazy" className="bm-img"
          style={{ position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover" }}
          onError={e=>{e.target.style.display="none";e.target.parentElement.style.background="#E2E8F0";}} />
      </div>
      <div style={{ flex:1,display:"flex",flexDirection:"column" }}>
        <div style={{ fontWeight:700,fontSize:13,lineHeight:1.3,marginBottom:3,overflow:"hidden",display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical" }}>{p.name}</div>
        <div style={{ fontSize:12,color:"#94A3B8",marginBottom:8 }}>{p.w}</div>
        <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-end",gap:4,marginTop:"auto" }}>
          <div>
            <div style={{ fontWeight:800,fontSize:15,color:"#0F172A" }}>{Rs(p.price)}</div>
            {p.mrp > p.price && <div style={{ fontSize:11,color:"#94A3B8",textDecoration:"line-through" }}>{Rs(p.mrp)}</div>}
          </div>
          <div onClick={e=>e.stopPropagation()}>
            {qty > 0
              ? <Stepper qty={qty} onAdd={()=>onUpdate(qty+1)} onSub={()=>onUpdate(qty-1)} />
              : <button data-testid={`add-to-cart-${p.id}`} className="bm-add"
                  onClick={e=>{e.stopPropagation();onAdd();}}
                  style={{ border:`2px solid ${EM}`,background:"#fff",color:EM,borderRadius:18,padding:"5px 12px",fontWeight:700,fontSize:11,cursor:"pointer",transition:"all 200ms",whiteSpace:"nowrap" }}>ADD</button>
            }
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Product Row ────────────────────────────────────────────────────────

function ProductRow({ title, sub, prods, cart, onAdd, onUpd, nav }) {
  const ref = useRef(null);
  const sc = d => ref.current?.scrollBy({ left:d*360, behavior:"smooth" });
  const qty = id => cart.find(i=>i.id===id)?.qty || 0;
  return (
    <section style={{ marginBottom:36 }}>
      <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-end",marginBottom:12 }}>
        <div>
          <h2 style={{ fontWeight:800,fontSize:19,color:"#0F172A",margin:0 }}>{title}</h2>
          {sub && <p style={{ fontSize:12,color:"#64748B",marginTop:3,marginBottom:0 }}>{sub}</p>}
        </div>
        <div style={{ display:"flex",gap:6 }}>
          {[["‹",-1],["›",1]].map(([c,d])=>(
            <button key={c} onClick={()=>sc(d)} className="bm-row-btn" aria-label={d<0?"left":"right"}
              style={{ width:32,height:32,borderRadius:"50%",border:"1px solid #E2E8F0",background:"#fff",cursor:"pointer",fontSize:17,display:"flex",alignItems:"center",justifyContent:"center",color:"#64748B",transition:"background 200ms" }}>{c}</button>
          ))}
        </div>
      </div>
      <div ref={ref} className="bm-no-scroll" style={{ display:"flex",gap:10,overflowX:"auto",scrollSnapType:"x mandatory",paddingBottom:4 }}>
        {prods.map(p => (
          <div key={p.id} style={{ flexShrink:0,width:"44vw",maxWidth:200,scrollSnapAlign:"start" }}>
            <ProductCard p={p} qty={qty(p.id)} onAdd={()=>onAdd(p)} onUpdate={q=>onUpd(p.id,q)} nav={nav} />
          </div>
        ))}
      </div>
    </section>
  );
}

// ── Hero Banner ────────────────────────────────────────────────────────

function HeroBanner({ nav }) {
  const [idx, setIdx] = useState(0);
  useEffect(() => {
    const t = setInterval(()=>setIdx(a=>(a+1)%BANNERS.length), 5000);
    return ()=>clearInterval(t);
  }, []);
  const b = BANNERS[idx];
  return (
    <div style={{ borderRadius:20,overflow:"hidden",position:"relative",height:210,marginBottom:28,cursor:"pointer",flexShrink:0 }}
      onClick={()=>nav({type:"home"})}>
      <img src={b.img} alt="Hero Banner" loading="lazy"
        style={{ width:"100%",height:"100%",objectFit:"cover",position:"absolute",inset:0 }}
        onError={e=>{e.target.style.display="none";e.target.parentElement.style.background=EM;}} />
      <div style={{ position:"absolute",inset:0,background:"linear-gradient(to top,rgba(0,0,0,.55) 0%,rgba(0,0,0,.1) 50%,transparent 100%)" }} />
      <div style={{ position:"absolute",inset:0,padding:"22px 28px",display:"flex",flexDirection:"column",justifyContent:"flex-end" }}>
        <div className="bm-pulse" style={{ background:LM,color:"#14532D",fontSize:10,fontWeight:800,padding:"3px 10px",borderRadius:18,display:"inline-flex",alignItems:"center",gap:4,marginBottom:12,width:"fit-content" }}>⚡ 10 MIN DELIVERY</div>
        <h2 style={{ fontWeight:900,fontSize:26,color:"#fff",lineHeight:1.15,margin:"0 0 8px",whiteSpace:"pre-line" }}>{b.title}</h2>
        <p style={{ color:"rgba(255,255,255,.85)",fontSize:13,margin:"0 0 16px" }}>{b.sub}</p>
        <div onClick={e=>e.stopPropagation()}>
          <button style={{ background:"#fff",color:EM,border:"none",borderRadius:20,padding:"9px 22px",fontWeight:800,fontSize:13,cursor:"pointer" }}>{b.cta} →</button>
        </div>
      </div>
      <div style={{ position:"absolute",bottom:14,left:"50%",transform:"translateX(-50%)",display:"flex",gap:5,alignItems:"center" }}>
        {BANNERS.map((_,i)=>(
          <button key={i} onClick={e=>{e.stopPropagation();setIdx(i);}}
            style={{ width:i===idx?22:5,height:5,borderRadius:3,background:i===idx?LM:"rgba(255,255,255,.5)",border:"none",cursor:"pointer",transition:"width 300ms",padding:0 }} />
        ))}
      </div>
    </div>
  );
}

// ── Category Grid ──────────────────────────────────────────────────────

function CategoryGrid({ nav }) {
  return (
    <section style={{ marginBottom:36 }}>
      <h2 style={{ fontWeight:800,fontSize:19,color:"#0F172A",margin:"0 0 3px" }}>Shop by Category</h2>
      <p style={{ fontSize:12,color:"#64748B",margin:"0 0 14px" }}>All 16 categories · in 10 mins</p>
      <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(76px,1fr))",gap:8 }}>
        {CATS.map((c,i)=>(
          <div key={c.slug} data-testid={`category-${c.slug}`} className="bm-cat bm-up"
            onClick={()=>nav({type:"category",slug:c.slug})}
            style={{ background:"#fff",borderRadius:14,padding:8,cursor:"pointer",border:"1px solid #E2E8F0",display:"flex",flexDirection:"column",alignItems:"center",gap:6,animationDelay:`${i*20}ms`,boxShadow:"none" }}>
            <div style={{ width:"100%",aspectRatio:"1",borderRadius:10,overflow:"hidden",background:c.bg }}>
              <img src={c.img} alt={c.name} loading="lazy" style={{ width:"100%",height:"100%",objectFit:"cover" }}
                onError={e=>{e.target.style.display="none";}} />
            </div>
            <div style={{ fontWeight:700,fontSize:10,textAlign:"center",lineHeight:1.3,color:"#1E293B",wordBreak:"break-word" }}>{c.name}</div>
          </div>
        ))}
      </div>
    </section>
  );
}

// ── Header ─────────────────────────────────────────────────────────────

function Header({ cart, setCartOpen, onMenuOpen, user, setUser, nav, goBack, canGoBack }) {
  const [q, setQ] = useState("");
  const [sugg, setSugg] = useState([]);
  const debRef = useRef(null);
  const cartCount = cart.reduce((s,i)=>s+i.qty,0);

  const onSearch = v => {
    setQ(v);
    clearTimeout(debRef.current);
    debRef.current = setTimeout(()=>{
      setSugg(v.length>1 ? PRODS.filter(p=>p.name.toLowerCase().includes(v.toLowerCase())).slice(0,7) : []);
    },200);
  };

  return (
    <div style={{ zIndex:40,background:"rgba(255,255,255,.97)",backdropFilter:"blur(20px)",borderBottom:"1px solid #E2E8F0",flexShrink:0,position:"relative" }}>
      {/* Row 1 — Logo + Icons */}
      <div style={{ padding:"0 16px",height:54,display:"flex",alignItems:"center",gap:10 }}>
        {canGoBack ? (
          <button onClick={goBack} style={{ background:"none",border:"none",cursor:"pointer",padding:"4px",borderRadius:8,display:"flex",alignItems:"center",color:"#0F172A",flexShrink:0 }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M19 12H5"/><polyline points="12 19 5 12 12 5"/></svg>
          </button>
        ) : null}
        <div onClick={()=>nav({type:"home"})} style={{ display:"flex",alignItems:"center",gap:7,cursor:"pointer",flexShrink:0 }}>
          <div style={{ width:32,height:32,background:EM,borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center",color:LM,fontWeight:900,fontSize:17 }}>B</div>
          <span style={{ fontWeight:800,fontSize:17,color:"#0F172A" }}>Mart</span>
        </div>
        <div style={{ flex:1 }} />
        {/* Cart icon */}
        <button onClick={()=>setCartOpen(true)} style={{ position:"relative",background:"none",border:"none",cursor:"pointer",padding:"6px",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",color:"#0F172A" }}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>
          {cartCount>0 && (
            <span style={{ position:"absolute",top:2,right:2,background:EM,color:"#fff",borderRadius:"50%",width:16,height:16,fontSize:9,fontWeight:900,display:"flex",alignItems:"center",justifyContent:"center",lineHeight:1 }}>{cartCount}</span>
          )}
        </button>
        {/* Hamburger */}
        <button onClick={onMenuOpen} style={{ background:"none",border:"none",cursor:"pointer",padding:"6px",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",color:"#0F172A" }}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/></svg>
        </button>
      </div>
      {/* Row 2 — Search bar */}
      <div style={{ padding:"0 16px 10px",position:"relative" }}>
        <div style={{ display:"flex",alignItems:"center",background:"#F8FAFC",borderRadius:11,border:"1.5px solid #E2E8F0",padding:"0 12px",gap:8,height:40,transition:"border 200ms" }}
          onFocusCapture={e=>e.currentTarget.style.borderColor=LM}
          onBlurCapture={e=>{e.currentTarget.style.borderColor="#E2E8F0";setTimeout(()=>setSugg([]),200);}}>
          <span style={{ color:"#94A3B8",fontSize:14,flexShrink:0 }}>🔍</span>
          <input data-testid="search-input" value={q}
            onChange={e=>onSearch(e.target.value)}
            onKeyDown={e=>{if(e.key==="Enter"&&q){nav({type:"search",q});setSugg([]);}}}
            placeholder='Search "milk", "bread", "atta"...'
            style={{ flex:1,border:"none",outline:"none",background:"transparent",fontSize:13,fontFamily:"inherit",height:"100%" }} />
        </div>
        {sugg.length>0 && (
          <div style={{ position:"absolute",top:"calc(100% - 2px)",left:16,right:16,background:"#fff",borderRadius:11,boxShadow:"0 8px 32px rgba(0,0,0,.12)",border:"1px solid #E2E8F0",zIndex:100,overflow:"hidden" }}>
            {sugg.map(p=>(
              <div key={p.id} className="bm-dd-row" onClick={()=>{nav({type:"product",id:p.id});setSugg([]);setQ("");}}
                style={{ display:"flex",alignItems:"center",gap:10,padding:"8px 12px",cursor:"pointer",borderBottom:"1px solid #F8FAFC",transition:"background 150ms" }}>
                <img src={p.img} alt={p.name} style={{ width:34,height:34,borderRadius:7,objectFit:"cover",flexShrink:0 }} onError={e=>e.target.style.display="none"} />
                <div style={{ flex:1,overflow:"hidden" }}>
                  <div style={{ fontSize:12,fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap" }}>{p.name}</div>
                  <div style={{ fontSize:10,color:"#94A3B8" }}>{p.w}</div>
                </div>
                <div style={{ fontWeight:800,fontSize:12,color:EM,flexShrink:0 }}>{Rs(p.price)}</div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Cart Drawer ─────────────────────────────────────────────────────────

function CartDrawer({ open, onClose, cart, onUpd, nav, cartTotal }) {
  const del = cartTotal>=199?0:25;
  const total = cartTotal+del;
  return (
    <>
      {open && <div onClick={onClose} style={{ position:"absolute",inset:0,background:"rgba(0,0,0,.45)",zIndex:60 }} />}
      <div style={{ position:"absolute",top:0,right:0,bottom:0,width:"min(380px,100%)",background:"#fff",zIndex:61,transform:open?"translateX(0)":"translateX(100%)",transition:"transform 340ms cubic-bezier(.16,1,.3,1)",display:"flex",flexDirection:"column",boxShadow:"-8px 0 32px rgba(0,0,0,.15)" }}>
        <div style={{ padding:"16px 20px",borderBottom:"1px solid #F1F5F9",display:"flex",justifyContent:"space-between",alignItems:"center",flexShrink:0 }}>
          <h3 style={{ fontWeight:800,fontSize:18,margin:0,color:"#0F172A" }}>Your Cart</h3>
          <button onClick={onClose} aria-label="Close cart" style={{ width:30,height:30,borderRadius:"50%",border:"1px solid #E2E8F0",background:"#fff",cursor:"pointer",fontSize:15,display:"flex",alignItems:"center",justifyContent:"center" }}>✕</button>
        </div>
        {cart.length===0 ? (
          <div style={{ flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:28,gap:14,textAlign:"center" }}>
            <div style={{ fontSize:56 }}>🛍️</div>
            <h4 style={{ fontWeight:800,fontSize:17,margin:0 }}>Your cart is empty</h4>
            <p style={{ color:"#64748B",fontSize:13 }}>Add items to get them delivered in 10 minutes</p>
            <button onClick={onClose} style={{ background:EM,color:"#fff",border:"none",borderRadius:22,padding:"11px 28px",fontWeight:700,cursor:"pointer",fontSize:14 }}>Continue Shopping</button>
          </div>
        ) : (
          <>
            <div style={{ background:"#ECFDF5",padding:"8px 20px",fontSize:12,fontWeight:700,color:"#065F46",borderBottom:"1px solid #D1FAE5",flexShrink:0 }}>✨ Delivery in 10 minutes · Bangalore</div>
            <div className="bm-no-scroll" style={{ flex:1,overflowY:"auto",padding:"0 20px" }}>
              {cart.map(item=>(
                <div key={item.id} style={{ display:"flex",gap:10,padding:"12px 0",borderBottom:"1px solid #F8FAFC",alignItems:"center" }}>
                  <div style={{ width:48,height:48,borderRadius:9,overflow:"hidden",flexShrink:0,background:"#F8FAFC" }}>
                    <img src={item.img} alt={item.name} style={{ width:"100%",height:"100%",objectFit:"cover" }} onError={e=>e.target.style.display="none"} />
                  </div>
                  <div style={{ flex:1,minWidth:0 }}>
                    <div style={{ fontWeight:600,fontSize:12,lineHeight:1.3,marginBottom:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap" }}>{item.name}</div>
                    <div style={{ fontSize:10,color:"#94A3B8",marginBottom:4 }}>{item.subcat==="fruits"||item.subcat==="vegetables" ? (item.qty*0.5)+"kg" : item.w}</div>
                    <div style={{ fontWeight:800,fontSize:13,color:EM }}>{Rs(item.price*item.qty)}</div>
                  </div>
                  <div style={{ display:"flex",flexDirection:"column",alignItems:"flex-end",gap:7 }}>
                    <Stepper qty={item.qty} onAdd={()=>onUpd(item.id,item.qty+1)} onSub={()=>onUpd(item.id,item.qty-1)} />
                    <button onClick={()=>onUpd(item.id,0)} style={{ fontSize:10,color:"#EF4444",background:"none",border:"none",cursor:"pointer",padding:0 }}>Remove</button>
                  </div>
                </div>
              ))}
            </div>
            <div style={{ borderTop:"1px solid #E2E8F0",padding:"14px 20px",flexShrink:0 }}>
              {[["Subtotal",Rs(cartTotal),false],["Delivery",del===0?"FREE ✓":Rs(del),del===0]].map(([l,v,g])=>(
                <div key={l} style={{ display:"flex",justifyContent:"space-between",fontSize:12,color:"#64748B",marginBottom:6 }}>
                  <span>{l}</span><span style={{ fontWeight:600,color:g?"#16A34A":"#0F172A" }}>{v}</span>
                </div>
              ))}
              {del>0 && <div style={{ fontSize:10,color:"#94A3B8",marginBottom:8,background:"#FFFBEB",padding:"6px 10px",borderRadius:7 }}>Add {Rs(199-cartTotal)} more for free delivery</div>}
              <div style={{ display:"flex",justifyContent:"space-between",fontWeight:900,fontSize:16,margin:"10px 0 14px" }}>
                <span>Total</span><span style={{ color:EM }}>{Rs(total)}</span>
              </div>
              <button onClick={()=>{onClose();nav({type:"checkout"});}}
                style={{ width:"100%",background:EM,color:"#fff",border:"none",borderRadius:22,padding:"13px 20px",fontWeight:700,fontSize:14,cursor:"pointer" }}>
                Proceed to Checkout · {Rs(total)}
              </button>
            </div>
          </>
        )}
      </div>
    </>
  );
}

